import vex
from typing import Set, Dict

class DelegationTracker:
    def __init__(self):
        self.call_stack: Dict[str, Set[str]] = {}

    @vex.guardrail(before_agent_callback=True)
    def prevent_circular_delegation(self, inputs: dict, agent_id: str) -> dict:
        current_stack = self.call_stack.get(inputs.get('session_id', 'default'), set())

        if agent_id in current_stack:
            raise vex.ViolationError(f"Circular dependency detected: {agent_id} called recursively")

        current_stack.add(agent_id)
        self.call_stack[inputs.get('session_id', 'default')] = current_stack

        vex.log.audit(f"Delegation trace: {' -> '.join(list(current_stack))}")
        return inputs

tracker = DelegationTracker()
triage_agent = Agent(callbacks=[tracker.prevent_circular_delegation])

import vex
import json
from google.adk.tools import ToolResponse

@vex.guardrail(before_agent_callback=True)
def validate_tool_responses(self, inputs: dict) -> dict:
    if 'tool_results' in inputs:
        expected_schema = {
            "diagnosis": "str",
            "confidence": "float between 0-1",
            "recommendations": "list[str]"
        }

        for i, result in enumerate(inputs['tool_results']):
            try:
                parsed = json.loads(result)
                if not isinstance(parsed.get('confidence'), float) or not 0 <= parsed['confidence'] <= 1:
                    raise ValueError(f"Invalid confidence score in tool {i}")
                vex.log.metric('tool_validation', {'valid': True, 'tool_id': i})
            except Exception as e:
                vex.block(f"Tool {i} format violation: {e}")
                inputs['tool_results'][i] = json.dumps({"error": "format_validation_failed"})
    return inputs

lab_agent = Agent(callbacks=[validate_tool_responses])
